using System;
using System.Linq;
using Generator.Model;

namespace Generator.Renderer.Public;

internal static class ClassConstructors
{
    public static string Render(GirModel.Class cls)
    {
        return $$"""
                 using System;
                 using System.Linq;
                 using GObject;
                 using System.Runtime.InteropServices;

                 #nullable enable

                 namespace {{Namespace.GetPublicName(cls.Namespace)}};

                 // AUTOGENERATED FILE - DO NOT MODIFY

                 public partial class {{cls.Name}}
                 {
                     {{RenderFactoryMethodWithConstructArguments(cls)}}

                     {{cls.Constructors
                         .Select(ConstructorRenderer.Render)
                         .Join(Environment.NewLine)}}
                 }
                 """;
    }

    private static string RenderFactoryMethodWithConstructArguments(GirModel.Class cls)
    {
        var owned = Class.IsInitiallyUnowned(cls) ? "false" : "true";

        var newKeyWord = Class.IsGObjectObject(cls) ? string.Empty : "new ";

        return $$"""
                 /// <summary>
                 /// Creates a new {{cls.Name}} and sets the properties specified by the construct arguments.
                 /// </summary>
                 /// <param name="constructArguments">The properties to set.</param>
                 public static {{newKeyWord}}{{cls.Name}} NewWithProperties(GObject.ConstructArgument[] constructArguments)
                 {
                     var handle = GObject.Internal.Object.NewWithProperties(
                        objectType: GetGType(),
                        nProperties: (uint) constructArguments.Length,
                        names: GLib.Internal.Utf8StringArraySizedOwnedHandle.Create(constructArguments.Select(x => x.Name).ToArray()),
                        values: GObject.Internal.ValueArray2OwnedHandle.Create(constructArguments.Select(x => x.Value).ToArray())
                    );
                     
                     return {{cls.Namespace.Name}}.{{cls.Name}}.CreateIntern(handle, {{owned}});
                 }
                 """;
    }
}
